#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


// ***** Flexis rotating caleidoscope code *****

vec2 cntr = vec2(q13,q14); float sin = q11; float cos = q12; float scale = q15;
vec2 uv_r = (vUv-cntr)*uAspect.xy;
       uv_r = scale*vec2( cos*uv_r.x - sin*uv_r.y, sin*uv_r.x + cos*uv_r.y); // rotation
       uv_r = cntr + uv_r*uAspect.zw;
       uv_r = 1.0 - abs( fract( uv_r * 0.5 ) * 2.0 - 1.0 ); // mirror

sin = q17; cos = q18; scale = q16;
vec2 uv_rr = (uv_r-cntr);
       uv_rr = scale*vec2( cos*uv_rr.x - sin*uv_rr.y, sin*uv_rr.x + cos*uv_rr.y); // counter-rotation
       uv_rr = cntr + (uv_rr);

vec2 caleidoscope_uv = uv_rr;

// ***** :) *****


float t = q22;
vec2 c = ((uv_rr-0.5));
float1 ang_hq = atan(c.x,c.y);
vec2 spiral = vec2(ang_hq*q21*1.5,0.666*log(length(c))-ang_hq*q21+t);
spiral = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 ))*vec2(0.96,1.02); // mirror



    vec2 d = uTexSize.zw*12;
    vec3 dx = ( GetBlur1(vUv + vec2(1,0)*d) - GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv-vec2(0,1)*d) );
    vec2 my_uv = vUv + vec2(dx.y,dy.y)*0.1;

vec3 re;

//vUv = vUv + 0.02*vec2(cos(vUv.y*27),sin(vUv.x*39));
vec2 m = vec2(1-q4,q8);
vec2 bg_uv = m + (vUv-m)*0.992; // subtle 3D shadow drop
vec2 mid_uv = m + (vUv-m)*0.996;
ret = mix( vec3(0,0,0.2), vec3(0.3,0,1),texture( sampler_fw_main, bg_uv).y);
ret = mix(ret, vec3(1,1,0), max(GetBlur1(bg_uv).z*1.5,texture( sampler_main, mid_uv).z)); // if that isn't a cool glow effect?
ret *= 1-GetBlur1(bg_uv).x*2; // drop shadow
ret = mix( ret, vec3(1,0.1,0.4),texture( sampler_fw_main, vUv).x);



ret = GetPixel(clamp01(spiral));
re = texture( sampler_rand00, my_uv);
ret = mix( texture(sampler_rand01,my_uv), re, ret.x);
ret-=roam_sin.wzy*roam_cos.zxy;

  fragColor = ret;
}
